from pydantic import BaseModel, validator, Field
from typing import Optional
from datetime import date, datetime

class OrderRecord(BaseModel):
    order_id: int
    customer_id: int
    product_sku: str
    quantity: int = Field(gt=0, description="Must be positive")
    unit_price: float = Field(ge=0.0)
    order_date: date
    discount_pct: Optional[float] = Field(None, ge=0.0, le=1.0)
    is_returned: bool = False

    # Custom validator: accept multiple date formats
    @validator("order_date", pre=True)
    def parse_order_date(cls, v):
        if isinstance(v, date):
            return v
        for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%d-%m-%Y"):
            try:
                return datetime.strptime(str(v), fmt).date()
            except ValueError:
                continue
        raise ValueError(f"Cannot parse date: {v}")

    # Custom validator: normalize boolean-like strings
    @validator("is_returned", pre=True)
    def parse_bool(cls, v):
        if isinstance(v, bool):
            return v
        if isinstance(v, str):
            return v.strip().lower() in ("true", "yes", "1", "y")
        return bool(v)


