from dataclasses import dataclass
from typing import Dict, Set, List, Any

@dataclass
class SchemaDiff:
    added_columns: Set[str]
    removed_columns: Set[str]
    type_changes: Dict[str, tuple]   # col → (old_type, new_type)

def infer_schema(df: pd.DataFrame) -> Dict[str, str]:
    """Return {column_name: dtype_string} for a DataFrame."""
    return {col: str(dtype) for col, dtype in df.dtypes.items()}

def diff_schemas(
    expected: Dict[str, str],
    actual: Dict[str, str]
) -> SchemaDiff:
    expected_cols = set(expected.keys())
    actual_cols = set(actual.keys())

    added = actual_cols - expected_cols
    removed = expected_cols - actual_cols

    type_changes = {}
    for col in expected_cols & actual_cols:
        if expected[col] != actual[col]:
            type_changes[col] = (expected[col], actual[col])

    return SchemaDiff(
        added_columns=added,
        removed_columns=removed,
        type_changes=type_changes
    )

# Usage
expected_schema = {
    "order_id": "int64",
    "customer_id": "int64",
    "unit_price": "float64",
    "order_date": "datetime64[ns]",
}

df_today = pd.read_csv("orders_today.csv", parse_dates=["order_date"])
actual_schema = infer_schema(df_today)

diff = diff_schemas(expected_schema, actual_schema)

if diff.added_columns:
    print(f"⚠️  New columns detected: {diff.added_columns}")
if diff.removed_columns:
    print(f"🚨 Missing columns: {diff.removed_columns}")
if diff.type_changes:
    for col, (old, new) in diff.type_changes.items():
        print(f"⚠️  Type change in '{col}': {old} → {new}")

from datetime import datetime, date
import pandas as pd
from typing import Optional, Union

# Common date formats seen in the wild
DATE_FORMATS = [
    "%Y-%m-%d",          # 2024-06-15   (ISO 8601 — preferred)
    "%d/%m/%Y",          # 15/06/2024   (European)
    "%m/%d/%Y",          # 06/15/2024   (American)
    "%d-%m-%Y",          # 15-06-2024
    "%Y%m%d",            # 20240615     (compact)
    "%d %b %Y",          # 15 Jun 2024
    "%B %d, %Y",         # June 15, 2024
    "%Y-%m-%dT%H:%M:%S", # 2024-06-15T10:30:00  (ISO 8601 datetime)
]

def parse_date_flexible(value: Union[str, date, datetime, None]) -> Optional[date]:
    """Parse a date from any of several common formats."""
    if value is None:
        return None
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    if not isinstance(value, str) or value.strip() == "":
        return None
    value = value.strip()
    for fmt in DATE_FORMATS:
        try:
            return datetime.strptime(value, fmt).date()
        except ValueError:
            continue
    raise ValueError(f"Cannot parse date from '{value}' — no matching format")


# In pandas — vectorized date parsing
def parse_dates_column(series: pd.Series) -> pd.Series:
    """
    Try pd.to_datetime with multiple formats.
    Coerce unparseable values to NaT (not-a-time).
    """
    for fmt in DATE_FORMATS:
        try:
            parsed = pd.to_datetime(series, format=fmt, errors="coerce")
            # If most values parsed successfully, use this format
            success_rate = parsed.notna().mean()
            if success_rate > 0.9:
                return parsed
        except Exception:
            continue
    # Fallback: let pandas infer (slower but catches mixed formats)
    return pd.to_datetime(series, infer_datetime_format=True, errors="coerce")

from datetime import timezone
import pytz

def normalize_to_utc(dt: datetime) -> datetime:
    """Convert any datetime to UTC. Assume UTC if no tzinfo present."""
    if dt.tzinfo is None:
        # Naive datetime — assume it's UTC (document this assumption!)
        return dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)

